import fs from 'fs';
import path from 'path';
import { TaskStore } from './store';

const program = new Command();

program
  .option('--data <path>', 'Specify the data file path')
  .parse(process.argv);

const options = program.opts();

if (!options.data) {
  console.error('--data <path> is required');
  process.exit(1);
}

const dataFilePath = path.resolve(options.data);

if (!fs.existsSync(dataFilePath)) {
  fs.writeFileSync(dataFilePath, JSON.stringify({ tasks: [] }));
}

const taskStore = new TaskStore(dataFilePath);

program
  .command('add <title>')
  .description('Add a new task')
  .action(async (title) => {
    await taskStore.addTask(title);
    console.log('Task added');
  });

program
  .command('list')
  .description('List all tasks')
  .action(async () => {
    const tasks = await taskStore.listTasks();
    console.log(tasks);
  });

program
  .command('done <id>')
  .description('Mark a task as done')
  .action(async (id) => {
    await taskStore.markTaskAsDone(id);
    console.log('Task marked as done');
  });

program
  .command('remove <id>')
  .description('Remove a task')
  .action(async (id) => {
    await taskStore.removeTask(id);
    console.log('Task removed');
  });

program.parse(process.argv);
" }, {"path": "src/store.ts", "content": "import fs from 'fs';
import path from 'path';
import { v4 as uuidv4 } from 'uuid';

interface Task {
  id: string;
  title: string;
  completed: boolean;
}

export class TaskStore {
  private dataFilePath: string;

  constructor(dataFilePath: string) {
    this.dataFilePath = dataFilePath;
  }

  async addTask(title: string): Promise<void> {
    const tasks: Task[] = this.readTasks();
    tasks.push({ id: uuidv4(), title, completed: false });
    this.writeTasks(tasks);
  }

  async listTasks(): Promise<Task[]> {
    return this.readTasks();
  }

  async markTaskAsDone(id: string): Promise<void> {
    const tasks: Task[] = this.readTasks();
    const task = tasks.find(t => t.id === id);
    if (task) {
      task.completed = true;
      this.writeTasks(tasks);
    }
  }

  async removeTask(id: string): Promise<void> {
    const tasks: Task[] = this.readTasks();
    const updatedTasks = tasks.filter(t => t.id !== id);
    this.writeTasks(updatedTasks);
  }

  private readTasks(): Task[] {
    const data = fs.readFileSync(this.dataFilePath, 'utf-8');
    return JSON.parse(data).tasks || [];
  }

  private writeTasks(tasks: Task[]): void {
    fs.writeFileSync(this.dataFilePath, JSON.stringify({ tasks }, null, 2));
  }
}
